import React from 'react';

/**
 * Features component - Displays the main feature cards in a grid layout
 * @param {Object} props - Component props
 * @param {Array} props.features - Array of feature objects with icon, title, description, and bgColor
 */
const Features = ({ 
  features = [
    {
      icon: "📅",
      title: "Track Leave",
      description: "Monitor your EL, SL, and CL balances with real-time updates",
      bgColor: "#f3e8ff"
    },
    {
      icon: "✈️",
      title: "Plan Vacations",
      description: "Plan multi-day vacations with smart date validation",
      bgColor: "#dcfce7"
    },
    {
      icon: "🤖",
      title: "AI Insights",
      description: "Get smart recommendations for optimal vacation timing",
      bgColor: "#dbeafe"
    }
  ]
}) => {
  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-16">
      {features.map((feature, index) => (
        <div key={index} className="text-center">
          <div 
            className="w-16 h-16 mx-auto mb-4 rounded-full flex items-center justify-center"
            style={{backgroundColor: feature.bgColor}}
          >
            <span className="text-3xl">{feature.icon}</span>
          </div>
          <h3 className="text-lg font-semibold mb-2" style={{color: '#111827'}}>
            {feature.title}
          </h3>
          <p className="text-sm" style={{color: '#334155'}}>
            {feature.description}
          </p>
        </div>
      ))}
    </div>
  );
};

export default Features;
